def partition_labels(s: str):
    last = {ch: i for i, ch in enumerate(s)}
    res = []
    start = right = 0
    for i, ch in enumerate(s):
        right = max(right, last[ch])
        if i == right:
            res.append(i - start + 1)
            start = i + 1
    return res

